/// <summary>
/// Base class for Request message classes
/// </summary>
public abstract class KPMGCommon_RequestBase implements SysOperationValidatable
{
    DataAreaId dataAreaId;

}

Method.Source:
/// <summary>
/// Get and set the legal entity.
/// </summary>
/// <param name = "_value">The value to set.</param>
/// <returns>Current value of parameter.</returns>
[DataMember('LegalEntity', RequiredValidation::Mandatory)]
public DataAreaId parmDataAreaId(DataAreaId _value = dataAreaId)
{
    dataAreaId = _value;

    return dataAreaId;
}

/// <summary>
/// Validates the data contract values.
/// </summary>
/// <returns>
/// True if all the contract values are valid; otherwise, false.
/// </returns>
public boolean validate()
{
    return true;
}

/// <summary>
/// Checks failed for required proprties.
/// </summary>
/// <param name = "_methodName">The method name.</param>
/// <returns>The False value.</returns>
protected boolean checkFailedRequired(MethodName _methodName)
{
    error(strfmt("@KPMGCommon_GeneratePackingSlipForLoad:PropertyIsMandatoryError", this.getDataMemberAttributeName(_methodName)));

    return false;
}

/// <summary>
/// Gets the name property of the data member attribute by a method name.
/// </summary>
/// <param name = "_methodName">The method name.</param>
/// <returns>The name property of data member attribute.</returns>
protected str getDataMemberAttributeName(MethodName _methodName)
{
    str ret;

    if (_methodName)
    {
        SysDictMethod dictMethod = new SysDictMethod(UtilElementType::ClassInstanceMethod, classIdGet(this), _methodName);

        if (dictMethod && dictMethod.getAttribute(classStr(DataMemberAttribute)))
        {
            ret = (dictMethod.getAttribute(classStr(DataMemberAttribute)) as DataMemberAttribute).Name();
        }
    }

    return ret;
}
